// BusTrendChart.js
import React, { useEffect, useState } from "react";
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from "recharts";

const BusTrendChart = ({ buses }) => {
  const [chartData, setChartData] = useState([]);

  useEffect(() => {
    const now = new Date();
    const timestamp = now.toLocaleTimeString();

    const normalCount = buses.filter((b) => b.status === "normal").length;
    const ghostCount = buses.filter((b) => b.status === "ghost").length;
    const anomalyCount = buses.filter((b) => b.status === "anomaly").length;

    setChartData((prevData) => [
      ...prevData.slice(-19), // keep last 20 entries
      { time: timestamp, normal: normalCount, ghost: ghostCount, anomaly: anomalyCount },
    ]);
  }, [buses]);

  return (
    <ResponsiveContainer width={400} height={300}>
      <LineChart data={chartData}>
        <CartesianGrid strokeDasharray="3 3" />
        <XAxis dataKey="time" />
        <YAxis allowDecimals={false} />
        <Tooltip />
        <Legend />
        <Line type="monotone" dataKey="normal" stroke="green" strokeWidth={2} />
        <Line type="monotone" dataKey="ghost" stroke="red" strokeWidth={2} />
        <Line type="monotone" dataKey="anomaly" stroke="orange" strokeWidth={2} />
      </LineChart>
    </ResponsiveContainer>
  );
};

export default BusTrendChart;
